  def icon(name, css_class: "h-5 w-5")
    path = ICONS.fetch(name.to_s)
    raw(%(<svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor" class="#{css_class}" aria-hidden="true">#{path}</svg>))
  end

  def nav_link_class(current_path, target_path)
    active = current_path == target_path
    base = "ui-nav-tab"
    active ? "#{base} ui-nav-tab-active" : "#{base} ui-nav-tab-inactive"
  end

  def destination_chip_class(active)
    base = "ui-chip"
    active ? "#{base} ui-chip-active" : "#{base} ui-chip-inactive"
  end

  def status_badge_class(status)
    case status
    when "running" then "ui-badge-running"
    when "succeeded" then "ui-badge-succeeded"
    when "failed" then "ui-badge-failed"
    else "ui-badge-neutral"
    end
  end

  def status_badge(status)
    content_tag(:span, status, class: status_badge_class(status))
  end

  def ui_btn_class(variant = :primary, size: nil)
    classes = case variant.to_sym
    when :primary then "ui-btn-primary"
    when :secondary then "ui-btn-secondary"
    when :danger then "ui-btn-danger"
    when :warning then "ui-btn-warning"
    when :success then "ui-btn-success"
    when :ghost then "ui-btn-ghost"
    else "ui-btn-primary"
    end
    size == :xs ? "#{classes} ui-btn-xs" : classes
  end

  def sidebar_link_class(active)
    active ? "ui-sidebar-link ui-sidebar-link-active" : "ui-sidebar-link"
  end
end
